import React, { useEffect, useState } from "react";

function App() {
  const [weight, setWeight] = useState(20);
  const [feedback, setFeedback] = useState({ good: 0, bad: 0 });
  const [isAdmin, setIsAdmin] = useState(false);

  useEffect(() => {
    fetch("http://localhost:3000/weight")
      .then(res => res.json())
      .then(data => setWeight(data.weight));

    fetch("http://localhost:3000/feedback")
      .then(res => res.json())
      .then(data => setFeedback(data));
  }, []);

  const updateWeight = () => {
    fetch("http://localhost:3000/weight", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ weight })
    });
  };

  const sendFeedback = (type) => {
    fetch("http://localhost:3000/feedback", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ type })
    });
  };

  if (!isAdmin) {
    return (
      <div style={{ textAlign: "center", marginTop: 100 }}>
        <h2>User Page</h2>
        <button onClick={() => sendFeedback("good")}>👍 Good</button>
        <button onClick={() => sendFeedback("bad")}>👎 Bad</button>
        <br /><br />
        <button onClick={() => setIsAdmin(true)}>Go to Admin</button>
      </div>
    );
  }

  return (
    <div style={{ textAlign: "center", marginTop: 50 }}>
      <h2>Admin Dashboard</h2>

      <h3>Canary Weight: {weight}%</h3>
      <input
        type="range"
        min="0"
        max="100"
        value={weight}
        onChange={(e) => setWeight(e.target.value)}
      />
      <br />
      <button onClick={updateWeight}>Update</button>

      <h3>Feedback</h3>
      <p>👍 Good: {feedback.good}</p>
      <p>👎 Bad: {feedback.bad}</p>
    </div>
  );
}

export default App;
